query:
-- Nome do responsável da PACS Principal
SELECT id, cpf_cnpj FROM financial_responsibles WHERE id = 60001;

-- Preços de sistema para a PACS Principal
SELECT * FROM billing_system_unit_prices WHERE unit_id = 180001 AND ends_at IS NULL;

-- Preços de médicos para a PACS Principal
SELECT bdp.*, u.username FROM billing_doctor_unit_prices bdp
LEFT JOIN users u ON u.id = bdp.doctor_user_id
WHERE bdp.unit_id = 180001 AND bdp.ends_at IS NULL;

